create extension if not exists "pgcrypto";
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,full_name text not null,email text not null unique,role text not null default 'athlete' check (role in ('coach','athlete')),goal text,height_cm numeric,start_weight_kg numeric,created_at timestamptz not null default now());
create table if not exists public.checkins (id uuid primary key default gen_random_uuid(),athlete_id uuid not null references public.profiles(id) on delete cascade,date date not null,weight_kg numeric not null,blood_pressure text,pulse_bpm numeric,blood_sugar numeric,motivation text,well_being text,sleep_quality text,stool_quality text,additional_comment text,created_at timestamptz not null default now());
create table if not exists public.progress_photos (id uuid primary key default gen_random_uuid(),athlete_id uuid not null references public.profiles(id) on delete cascade,image_url text not null,note text,created_at timestamptz not null default now());
create table if not exists public.plans (id uuid primary key default gen_random_uuid(),athlete_id uuid not null references public.profiles(id) on delete cascade,title text not null,type text not null,content text not null,created_at timestamptz not null default now());
create table if not exists public.coach_notes (id uuid primary key default gen_random_uuid(),athlete_id uuid not null references public.profiles(id) on delete cascade,note text not null,created_at timestamptz not null default now());
alter table public.profiles enable row level security; alter table public.checkins enable row level security; alter table public.progress_photos enable row level security; alter table public.plans enable row level security; alter table public.coach_notes enable row level security;
create policy if not exists "profiles_select_own_or_coach" on public.profiles for select to authenticated using (auth.uid() = id or exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "profiles_insert_own" on public.profiles for insert to authenticated with check (auth.uid() = id);
create policy if not exists "checkins_select_own_or_coach" on public.checkins for select to authenticated using (athlete_id = auth.uid() or exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "checkins_insert_own" on public.checkins for insert to authenticated with check (athlete_id = auth.uid());
create policy if not exists "photos_select_own_or_coach" on public.progress_photos for select to authenticated using (athlete_id = auth.uid() or exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "photos_insert_own" on public.progress_photos for insert to authenticated with check (athlete_id = auth.uid());
create policy if not exists "plans_select_own_or_coach" on public.plans for select to authenticated using (athlete_id = auth.uid() or exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "plans_insert_coach_only" on public.plans for insert to authenticated with check (exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "coach_notes_select_own_or_coach" on public.coach_notes for select to authenticated using (athlete_id = auth.uid() or exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
create policy if not exists "coach_notes_insert_coach_only" on public.coach_notes for insert to authenticated with check (exists (select 1 from public.profiles me where me.id = auth.uid() and me.role = 'coach'));
